import { jsx, jsxs } from 'react/jsx-runtime';
import { classNames } from '../../helpers/classnames.js';
import { TreeProvider } from './TreeContext.js';
import { TreeNode } from './TreeNode/TreeNode.js';
import { TreeNodesWrapper } from './TreeNodesWrapper/TreeNodesWrapper.js';

const Tree = ({ title, size = 'small', children, amount = false, multiselect = false, onChange = () => null, onExpand, style, expandOnArrow = true, data, }) => {
    const renderFromObject = (data) => 
    // рекурсивно обходим дерево и строим из него дерево
    data.map(node => {
        const { children, ...treeProps } = node;
        return (
        // проверяем наличие дочерних компонентов в дереве и при их наличии продолжаем рекурсию
        jsx(TreeNode, { ...treeProps, children: children?.length ? renderFromObject(children) : null }));
    });
    return (jsx(TreeProvider, { callback: onChange, children: jsxs("ul", { "data-testid": "Tree", className: classNames(`tree-${size}`, 'dsb_tree'), style: style, role: "tree", children: [title && jsx(TreeNode, { className: "tree_title", id: "title", title: title }), jsx(TreeNodesWrapper, { size: size, amount: amount, multiselect: multiselect, expandOnArrow: expandOnArrow, onExpandCallback: onExpand, children: data ? renderFromObject(data) : children })] }) }));
};

export { Tree };
